function pick(obj, paths) {
  for (const p of paths) {
    const parts = p.split('.');
    let v = obj;
    for (const part of parts) v = v?.[part];
    if (v !== undefined && v !== null && v !== '') return v;
  }
  return '';
}

function cleanEmail(raw) {
  const value = String(raw || '');
  const match = value.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
  return match ? match[0].toLowerCase().trim() : value.toLowerCase().trim();
}

return items.map(item => {
  const j = item.json;
  const fromRaw = pick(j, ['from.value.0.address','from.email','headers.from','from','sender']);
  const nameRaw = pick(j, ['from.value.0.name','from.name','senderName']);
  const text = pick(j, ['textPlain','text','body.text','snippet','body']);
  return {
    json: {
      rawEmail: j,
      leadEmail: cleanEmail(fromRaw),
      leadName: nameRaw || '',
      subject: j.subject || '',
      messageText: String(text || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim(),
      gmailMessageId: j.id || j.messageId || j.message_id || '',
      gmailThreadId: j.threadId || j.thread_id || '',
      receivedAt: j.date || new Date().toISOString(),
      channel: 'Email'
    }
  };
});

